### Ink Static: Render Permanent Output Above Dynamic Content

Source: https://context7.com/vadimdemedes/ink/llms.txt

The Static component permanently renders items above all other output, ideal for displaying completed tasks or logs. It ignores modifications to existing items and only re-renders for new items. This example shows a task runner where completed tasks are displayed using Static.

```javascript
import React, {useState, useEffect} from 'react';
import {render, Static, Box, Text} from 'ink';

function TaskRunner() {
  const [completedTasks, setCompletedTasks] = useState([]);
  const [runningTask, setRunningTask] = useState(0);

  useEffect(() => {
    if (runningTask >= 10) return;

    const timer = setTimeout(() => {
      setCompletedTasks(prev => [
        ...prev,
        {
          id: prev.length,
          name: `Task #${prev.length + 1}`,
          duration: Math.floor(Math.random() * 1000)
        }
      ]);
      setRunningTask(prev => prev + 1);
    }, 500);

    return () => clearTimeout(timer);
  }, [runningTask]);

  return (
    <>
      <Static items={completedTasks} style={{marginBottom: 1}}>
        {(task, index) => (
          <Box key={task.id}>
            <Text color="green">✓ </Text>
            <Text>{task.name}</Text>
            <Text dimColor> ({task.duration}ms)</Text>
          </Box>
        )}
      </Static>

      <Box>
        <Text>
          {runningTask < 10 ? (
            <Text color="blue">⠋ Running task {runningTask + 1}...</Text>
          ) : (
            <Text color="green" bold>All tasks completed!</Text>
          )}
        </Text>
      </Box>
    </>
  );
}

render(<TaskRunner />);
```

